const AWS = require('aws-sdk');
const s3 = new AWS.S3({ apiVersion: '2006-03-01' });
const crypto = require('crypto');

const BUCKET_NAME = process.env.UPLOADS_BUCKET_NAME;
const MAX_FILE_SIZE = 10 * 1024 * 1024; // 10MB
const ALLOWED_MIME_TYPES = [
  'image/jpeg',
  'image/png',
  'image/gif',
  'application/pdf',
  'text/plain',
  'application/json'
];

exports.handler = async (event) => {
  try {
    // Validate request method
    if (event.httpMethod !== 'POST') {
      return {
        statusCode: 405,
        headers: { 'Allow': 'POST' },
        body: JSON.stringify({ error: 'Method not allowed' })
      };
    }

    // Validate content type
    const contentType = event.headers['content-type'] || event.headers['Content-Type'];
    if (!contentType || !contentType.includes('multipart/form-data')) {
      return {
        statusCode: 400,
        body: JSON.stringify({ error: 'Invalid content type. Must be multipart/form-data' })
      };
    }

    // Validate file size
    const contentLength = event.headers['content-length'] || event.headers['Content-Length'];
    if (contentLength && parseInt(contentLength) > MAX_FILE_SIZE) {
      return {
        statusCode: 413,
        body: JSON.stringify({ error: 'File too large. Maximum size is 10MB' })
      };
    }

    // Parse multipart form data
    const boundary = contentType.split('boundary=')[1];
    if (!boundary) {
      return {
        statusCode: 400,
        body: JSON.stringify({ error: 'Invalid multipart form data' })
      };
    }

    // Extract file data from body
    const bodyBuffer = Buffer.from(event.body, 'base64');
    const bodyString = bodyBuffer.toString('utf-8');
    
    // Extract file content and metadata
    const fileMatch = bodyString.match(/Content-Disposition: form-data; name="file"; filename="([^"]*)"\r\nContent-Type: ([^\r\n]*)\r\n\r\n([\s\S]*?)(?=\r\n--)/);
    if (!fileMatch) {
      return {
        statusCode: 400,
        body: JSON.stringify({ error: 'File not found in request' })
      };
    }

    const filename = fileMatch[1];
    const mimeType = fileMatch[2];
    const fileContent = fileMatch[3];

    // Validate filename
    if (!filename || filename.length > 255) {
      return {
        statusCode: 400,
        body: JSON.stringify({ error: 'Invalid filename' })
      };
    }

    // Validate MIME type
    if (!ALLOWED_MIME_TYPES.includes(mimeType)) {
      return {
        statusCode: 400,
        body: JSON.stringify({ error: 'Invalid file type' })
      };
    }

    // Generate secure filename
    const timestamp = Date.now();
    const randomString = crypto.randomBytes(16).toString('hex');
    const secureFilename = `${timestamp}-${randomString}-${filename.replace(/[^a-zA-Z0-9._-]/g, '')}`;

    // Upload to S3
    const params = {
      Bucket: BUCKET_NAME,
      Key: secureFilename,
      Body: fileContent,
      ContentType: mimeType,
      Metadata: {
        'uploaded-at': new Date().toISOString(),
        'source': 'api-upload'
      }
    };

    await s3.upload(params).promise();

    return {
      statusCode: 200,
      headers: {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': 'POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type'
      },
      body: JSON.stringify({
        message: 'File uploaded successfully',
        filename: secureFilename,
        size: fileContent.length
      })
    };

  } catch (error) {
    console.error('Upload error:', error);
    
    if (error.code === 'EntityTooLarge') {
      return {
        statusCode: 413,
        body: JSON.stringify({ error: 'File too large' })
      };
    }

    return {
      statusCode: 500,
      body: JSON.stringify({ error: 'Internal server error' })
    };
  }
};